import{_ as t,a,b as o,c as d,d as p,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Dropbox चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/dropbox.md","filePath":"hi/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"hi/upload/dropbox.md"};function h(b,e,u,m,f,g){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="dropbox-चैनल-जोड़ना" tabindex="-1">Dropbox चैनल जोड़ना <a class="header-anchor" href="#dropbox-चैनल-जोड़ना" aria-label="Permalink to &quot;Dropbox चैनल जोड़ना&quot;">​</a></h1><h2 id="पहले-क्या-चाहिए" tabindex="-1">पहले क्या चाहिए <a class="header-anchor" href="#पहले-क्या-चाहिए" aria-label="Permalink to &quot;पहले क्या चाहिए&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ज़रूरत</th><th>क्यों चाहिए</th></tr></thead><tbody><tr><td>Dropbox account</td><td>sign in और app authorize करने के लिए</td></tr><tr><td>Dropbox app</td><td><code>App Key</code> और <code>App Secret</code> generate करने के लिए</td></tr><tr><td>आपका ImgBed domain</td><td>OAuth redirect URI के लिए</td></tr><tr><td>उपलब्ध Dropbox storage</td><td>असली file storage location</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-dropbox-app-बनाएँ" tabindex="-1">Step 1: Dropbox App बनाएँ <a class="header-anchor" href="#step-1-dropbox-app-बनाएँ" aria-label="Permalink to &quot;Step 1: Dropbox App बनाएँ&quot;">​</a></h3><ol><li>Dropbox App Console खोलें:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>नया app बनाएँ।</li><li>access type के लिए चुनें:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>app को पहचानने लायक नाम दें, जैसे <code>imgbed-app</code>।</li><li>बनने के बाद app details page खोलें।</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>सुझाया गया। यह ImgBed के file storage तरीके से match करता है।</td></tr><tr><td><code>Full Dropbox</code></td><td>सुझाया नहीं गया। ImgBed को पूरे account access की ज़रूरत नहीं।</td></tr></tbody></table><p><img src="'+t+'" alt="Dropbox app बनाएँ" loading="lazy"></p><h3 id="step-2-redirect-uri-जोड़ें" tabindex="-1">Step 2: Redirect URI जोड़ें <a class="header-anchor" href="#step-2-redirect-uri-जोड़ें" aria-label="Permalink to &quot;Step 2: Redirect URI जोड़ें&quot;">​</a></h3><p>Dropbox app details page में OAuth या Redirect URI settings ढूँढें और जोड़ें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>अगर admin panel कई domains से use होता है, तो हर matching callback URL जोड़ें।</p><p><img src="'+a+'" alt="Redirect URI configure करें" loading="lazy"></p><h3 id="step-3-app-permissions-configure-करें" tabindex="-1">Step 3: App Permissions configure करें <a class="header-anchor" href="#step-3-app-permissions-configure-करें" aria-label="Permalink to &quot;Step 3: App Permissions configure करें&quot;">​</a></h3><p><code>Permissions</code> tab खोलें और कम से कम ये scopes enable करें:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>हाँ</td><td>account और quota information पढ़ता है</td></tr><tr><td><code>files.metadata.read</code></td><td>हाँ</td><td>path checks के लिए file और folder metadata पढ़ता है</td></tr><tr><td><code>files.metadata.write</code></td><td>हाँ</td><td>folders create और metadata write करता है</td></tr><tr><td><code>files.content.write</code></td><td>हाँ</td><td>files upload करता है। यह scope न हो तो <code>required scope &#39;files.content.write&#39;</code> error आता है।</td></tr><tr><td><code>files.content.read</code></td><td>सुझाया गया</td><td>download, preview और temporary file links allow करता है</td></tr></tbody></table><p>scopes चुनने के बाद page के नीचे <code>Submit</code> पर क्लिक करें।</p><p><img src="'+o+'" alt="Permissions जोड़ें" loading="lazy"></p><p>महत्वपूर्ण:</p><table tabindex="0"><thead><tr><th>Situation</th><th>क्या करें</th></tr></thead><tbody><tr><td>आपने scopes बदले</td><td>token authorization flow फिर चलाएँ और नया <code>Refresh Token</code> लें।</td></tr><tr><td>आपने reauthorize नहीं किया</td><td>पुराना token नई permissions नहीं पाएगा, इसलिए uploads फिर भी fail हो सकते हैं।</td></tr></tbody></table><h3 id="step-4-app-credentials-copy-करें" tabindex="-1">Step 4: App Credentials copy करें <a class="header-anchor" href="#step-4-app-credentials-copy-करें" aria-label="Permalink to &quot;Step 4: App Credentials copy करें&quot;">​</a></h3><p>Dropbox app page से ये दो values save करें:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-dropbox-channel-भरें" tabindex="-1">Step 5: Dropbox channel भरें <a class="header-anchor" href="#step-5-dropbox-channel-भरें" aria-label="Permalink to &quot;Step 5: Dropbox channel भरें&quot;">​</a></h3><p>Upload Settings में <code>Dropbox</code> चुनें और भरें:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>क्या डालें</th></tr></thead><tbody><tr><td>Channel name</td><td>पहचानने लायक नाम, जैसे <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>अभी खाली छोड़ें</td></tr><tr><td>Root directory</td><td>optional। default <code>imgbed</code>।</td></tr><tr><td>Note</td><td>optional</td></tr></tbody></table><p><img src="'+d+'" alt="Token लें" loading="lazy"></p><h3 id="step-6-refresh-token-लें" tabindex="-1">Step 6: Refresh Token लें <a class="header-anchor" href="#step-6-refresh-token-लें" aria-label="Permalink to &quot;Step 6: Refresh Token लें&quot;">​</a></h3><ol><li>ImgBed में <code>Get Token</code> पर क्लिक करें।</li><li>जिस Dropbox account को connect करना है उससे sign in करें।</li><li>authorization prompt approve करें।</li><li>callback page <code>Refresh Token</code> दिखाएगा।</li><li>इसे copy करें।</li><li>ImgBed में लौटकर <code>Refresh Token</code> field में paste करें।</li></ol><p><img src="'+p+'" alt="Token copy करें" loading="lazy"></p><h2 id="कैसे-जाँचें" tabindex="-1">कैसे जाँचें <a class="header-anchor" href="#कैसे-जाँचें" aria-label="Permalink to &quot;कैसे जाँचें&quot;">​</a></h2><table tabindex="0"><thead><tr><th>जाँच</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>save के बाद Dropbox channel दिखाई देता है।</td></tr><tr><td>Channel switch</td><td>channel enable किया जा सकता है।</td></tr><tr><td>Token saved</td><td>detail page दिखाता है कि <code>Refresh Token</code> save हुआ है।</td></tr><tr><td>Upload test</td><td>test image Dropbox app folder में दिखाई देती है।</td></tr></tbody></table><p>quota limits enabled हों तो quota query पर क्लिक करें। successful query के बाद channel card used space, total space और last update time दिखाता है।</p><p><img src="'+r+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed configuration incomplete कहता है</td><td>जाँचें कि <code>App Key</code>, <code>App Secret</code> और <code>Refresh Token</code> सभी भरे हैं।</td></tr><tr><td>Authorization successful है लेकिन <code>Refresh Token</code> नहीं दिखता</td><td><code>Get Token</code> फिर क्लिक करें और offline authorization flow use होना confirm करें।</td></tr><tr><td>Upload <code>required scope &#39;files.content.write&#39;</code> से fail होता है</td><td><code>files.content.write</code> enable करें, <code>Submit</code> क्लिक करें, फिर नया <code>Refresh Token</code> लें।</td></tr><tr><td>Callback fail होता है</td><td>confirm करें कि redirect URI <code>https://your-domain.com/api/oauth/dropbox/callback</code> है।</td></tr><tr><td>Files नहीं मिलतीं</td><td>confirm करें कि Dropbox app <code>App folder</code> mode में बना है।</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console खोलें</span></span>
<span class="line"><span>-&gt; app बनाएँ</span></span>
<span class="line"><span>-&gt; App folder access चुनें</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback जोड़ें</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write enable करें</span></span>
<span class="line"><span>-&gt; optional रूप से files.content.read enable करें</span></span>
<span class="line"><span>-&gt; Submit क्लिक करें</span></span>
<span class="line"><span>-&gt; App Key और App Secret copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में भरें</span></span>
<span class="line"><span>-&gt; Get Token क्लिक करें</span></span>
<span class="line"><span>-&gt; callback page से Refresh Token copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में paste करके save करें</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const v=s(c,[["render",h]]);export{y as __pageData,v as default};
